import type { PayloadAction } from '@reduxjs/toolkit';
import { createSlice } from '@reduxjs/toolkit';

import { PitchType } from '@/models/pitch-type';

interface MasterDataState {
  pitchTypes: PitchType[];
  deploymentCheckedAt: Date | null;
  maintenanceCheckedAt: Date | null;
}

const initialState: MasterDataState = {
  pitchTypes: [],
  deploymentCheckedAt: null,
  maintenanceCheckedAt: null,
};

const slice = createSlice({
  name: 'master',
  initialState,
  reducers: {
    setPitchTypes(
      state: MasterDataState,
      action: PayloadAction<PitchType[] | null>,
    ): void {
      state.pitchTypes = action.payload ?? [];
    },
    setDeploymentCheckedDate(
      state: MasterDataState,
      action: PayloadAction<Date>,
    ): void {
      const data = action.payload;
      state.deploymentCheckedAt = data;
    },
    setMaintenanceCheckedDate(
      state: MasterDataState,
      action: PayloadAction<Date>,
    ): void {
      const data = action.payload;
      state.maintenanceCheckedAt = data;
    },
  },
});

export const { reducer, actions } = slice;

